import React, { useState, useEffect } from 'react';
import PropTypes from 'prop-types';
import bridge from '@vkontakte/vk-bridge';

import { View, Panel, PanelHeader, Header, Button, Group, Cell, Div, Avatar, ScreenSpinner, ModalCard, File, Placeholder, FormItem, Input, ButtonGroup } from '@vkontakte/vkui';

import {  Icon56ErrorOutline, Icon28HourglassOutline, Icon56UserAddOutline, Icon56NewsfeedOutline, Icon56StoryOutline } from '@vkontakte/icons';

import imgStart from '../img/start.jpg';
import gifLoad from '../img/load.gif';
import imgGroups from '../img/groups.jpg';
import imgAccess from '../img/access.jpg';
import imgWarn from '../img/warn.jpg';
import axios from 'axios';
import $ from 'jquery';

const Home = ({ fetchedUser, setPopout, setModalError, setModal, setModalsList, setAnimate }) => {
	const [activePanel, setActivePanel] = useState('start');
	const [resultUrl, setResultUrl] = useState("");
	const [resultImageUrlPost, setResultImageUrlPost] = useState("");
	const [urlPublication, setUrlPublication] = useState("");
	const [textPublication, setTextPublication] = useState("");
	const [snackbar, setSnackbar] = useState(null);
	const [openGroupPage, setOpenGroupPage] = useState(1);
	const [openAccessPage, setOpenAccessPage] = useState(1);

	const [publicationPost, setPublicationPost] = useState(null);
	const [publicationStory, setPublicationStory] = useState(null);
	const [appId, setAppId] = useState(null);
	const [accessToken, setAccessToken] = useState(null);
	const [r, setR] = useState(true);
	const [texts, setTexts] = useState([ 
		['Подписаться на сообщество', 'Перейти к результату'],
		['Опубликовать результат', 'Перейти к результату']
	]);
	const [groupList, setGroupList] = useState([]);
	const [jsonResult, setJsonResult] = useState("");
	const [waitTime, setWaitTime] = useState(0);
	const [partnerName, setPartnerName] = useState("");
	const [nameStatus, setNameStatus] = useState("");
	const [nameBottom, setNameBottom] = useState("");

	let search = window.location.search;
	let getParams = search.split("?")[1];

	useEffect(() => {
		axios.get("user?" + getParams)
			.then(function (userInfo) {
				if(userInfo['data']['response']) {
				  	setR(userInfo['data']['response']['r']);
				  	setTexts(userInfo['data']['response']['texts']);
				  	setGroupList(userInfo['data']['response']['group']);
				  	setAppId(userInfo['data']['response']['app_id']);
				  	console.log(userInfo['data']['response']['app_id']);
				  	if(open == 0) {
						setOpenGroupPage(0);
				  		setOpenAccessPage(0);
				  	}
				  	setAnimate(true);
				  	setPopout(null);
				} else {
					setActivePanel('error_app');
				}
			})

			.catch(function (error_like) {
				setActivePanel('error_app');
			});
	}, []);

	function imageDownload (e) {
    	let url = window.URL || window.webkitURL;
		let form_data = new FormData();
        // typeDownload = "upload";
        let file_data = e.target.files[0]; 
        if(file_data.type == "image/jpeg" || file_data.type == "image/png") {
	        if(file_data.size > 20 * 1024 * 1024) {
	            openModalError(
	            	"Не удалось загрузить изображение",
	            	"Пожалуйста, загрузите фото размером менее 20 Мб"
	            );
	            form_data = new FormData(); 
	            $("#image").val("");
	        } else {
		        let img = new Image();
		        img.onload = function () {
		            if(this.width > 3000 || this.height > 3000) {
		                openModalError(
			            	"Не удалось загрузить изображение",
			            	"Пожалуйста, загрузите фото меньшего разрешения"
			            );
		                form_data = new FormData();
		                $("#image").val("");
		            } else {
		                form_data.append("image", file_data);
		                openResult = 1;
		                getResult('upload', form_data);
		                startGetResult();
		            }
		        };

		        img.src = url.createObjectURL(file_data);
	        }
        } else {
            openModalError(
            	"Не удалось загрузить изображение",
            	"Пожалуйста, загрузите PNG или JPG картинку"
            );
            form_data = new FormData(); 
            $("#image").val("");
        }
    }

    function openModalError ( header, text = "" ) {
    	setModalsList(
    		<ModalCard
		        id="modalError"
		        onClose={() => setModal(null)}
		        icon={<Icon56ErrorOutline />}
		        header={header}
		        subheader={text}
		        actions={
		          	<ButtonGroup size="l" mode="vertical" stretched>
			            <File
				            stretched="true"
				            size="l"
				            align="center"
				            id="image"
				            onChange={ (e) => { setModal(null); imageDownload(e); } }
			            >
			            	Загрузить другое фото
			            </File>
	          		</ButtonGroup>
		        }
	      	/>
    	);

      	setModal('modalError');
	}

	function openModal(name, name_2 = null) {
		if(name == 'group') {
			setModalsList(
				<ModalCard
			        id="group"
			        onClose={() => openModal(name_2)}
			        icon={<Icon56UserAddOutline />}
			        header="Понравилось наше приложение?"
			        subheader="Подписка самая лучшая благодарность для нас! Желаете подписаться?"
			        actions={
			          	<ButtonGroup size="s" stretched>
				            <Button
				              key="deny"
				              size="l"
				              mode="secondary"
				              stretched
				              onClick={() => setModal(name_2)}
				            >
				               Отказаться
				            </Button>
				            <Button
				              key="allow"
				              size="l"
				              mode="primary"
				              stretched
				              onClick={() => groupModal()}
				            >
				              Да, хорошо
				            </Button>
				        </ButtonGroup>
			        }
		      	/>
			);

			setModal('group');
		}

		if(name == 'post') {
			setModalsList(
				<ModalCard
			        id="post"
			        onClose={() => setModal(null)}
			        icon={<Icon56NewsfeedOutline />}
			        header="Поделитесь с друзьями, чтобы они могли узнать о себе!"
			        subheader="Для этого необходимо дать доступ."
			        actions={
			          	<ButtonGroup size="s" stretched>
				            <Button
				              key="deny"
				              size="l"
				              mode="secondary"
				              stretched
				              onClick={() => setModal(null)}
				            >
				               Отказаться
				            </Button>
				            <Button
				              key="allow"
				              size="l"
				              mode="primary"
				              stretched
				              onClick={() => openVKPost()}
				            >
				              Разрешить
				            </Button>
				        </ButtonGroup>
			        }
		      	/>
			);

			setModal('post');
		}

		if(name == 'story') {
			setModalsList(
				<ModalCard
			        id="story"
			        onClose={() => setModal(null)}
			        icon={<Icon56StoryOutline />}
			        header="Опубликуйте историю"
			        subheader="Опубликуйте историю с результатами"
			        actions={
			          	<ButtonGroup size="s" stretched>
				            <Button
				              key="deny"
				              size="l"
				              mode="secondary"
				              stretched
				              onClick={() => setModal(null)}
				            >
				              Закрыть
				            </Button>
				            <Button
				              key="allow"
				              size="l"
				              mode="primary"
				              stretched
				              onClick={() => openVKStory()}
				            >
				              Опубликовать
				            </Button>
				        </ButtonGroup>
			        }
		      	/> 
			);
			setModal('story');
		}

		if(name == 'error') {
			setModalsList(
				<ModalCard
			        id="error"
			        onClose={() => bridge.send("VKWebAppClose", {"status": "success"})}
			        icon={<Icon56ErrorOutline />}
			        header="Не удалось загрузить результат"
			        subheader="Пожалуйста, попробуйте позже"
		      	/> 
			);
			setModal('error');
		}
	}

	function getResult ( typeDownload, imageData = new FormData() ) {
		setPopout(<ScreenSpinner size='large' />);

		axios({
			method: "post",
			url: "image?type="+typeDownload+"&" + getParams,
			data: imageData
		})

		.then(function (response) {
			if(response['data']['server']) {
				let server = response['data']['server'];
				setTimeout(function () {
				    let checkResult = setInterval(function () {
				    	axios.get("checkDoneResults?server="+server+"&" + getParams)
				    	.then(function (dataCheckResult) {
				    		if(dataCheckResult["data"]["status"] == 1) {
				    			clearInterval(checkResult);
				    			axios.get("image?type=getResult&server="+server+"&" + getParams)
				    			.then(function (dataResult) {
				    				setJsonResult(dataResult["data"]);
				    			});
				    		} else {
				    			if(dataCheckResult["data"]["status"] == "deleted") {
				    				setJsonResult(dataCheckResult["data"]["response"]);
				    				clearInterval(checkResult);
				    			}
				    		}
				    	});
				    }, 3000);
			    }, 10000);
			} else {
				setJsonResult(response['data']);
			}
		})

		.catch(function (error) {
		    setJsonResult({ error: "error load" });
		});
	};


	function openResult (startPublication = 0) {
		if(jsonResult == "") {
			console.log('wait open');

			if(waitTime >= 10) {
				setWaitTime(0);
				setSnackbar(
					<Snackbar
				        onClose={() => setSnackbar(null)}
				        duration={7000}
				        before={
				            <Icon28HourglassOutline style={{ color: 'var(--vkui--color_background_accent)', marginLeft: "5px" }}/> 
				        }
				    >
				        Совсем скоро результат будет готов! Пожалуйста, не покидайте приложение
				    </Snackbar>
				);
			}

			setWaitTime(waitTime + 0.5);
			setTimeout(function () {
				openResult(startPublication);
			}, 500);
		} else {
			console.log('open');
			setPopout(null);
			setSnackbar(null);

			if(jsonResult['error']) {
				setActivePanel('error');
			} else {
				setResultImageUrlPost(jsonResult["post"]);
                setResultUrl(jsonResult["image_url"]);
                setUrlPublication(jsonResult["url_publication"]);
                setTextPublication(jsonResult["text"]);
                setActivePanel('result');

                if(startPublication == 1) {
					setPopout(<ScreenSpinner size='large' />);
					setTimeout(function () {
						publicationResult('post');
					}, 500);
				} else {
					if(openGroupPage == 1) {
						openModal('group', 'post');
					} else {
						openModal('post');
					}
				}
			}
		}
	}

	function publicationResult (type = 'post') {
		let token = null;
		setPopout(<ScreenSpinner size='large' />);
		console.log('access null app_id ' + appId);
		bridge.send("VKWebAppGetAuthToken", {"app_id": appId, "scope": "photos"})
            .then(data => {
            	token = data["access_token"];
            	console.log("success: ");
            	console.log(data);

		        bridge.send("VKWebAppCallAPIMethod", {"method": "photos.getAlbums", "params": {"owner_id": fetchedUser.id, "v":"5.131", "access_token":token}})
				    .then(data => {
				        let album_id = 0;
				        for (const [key, value] of Object.entries(data["response"]["items"])) {
				        	if(value["title"] == "Стилист") {
				            	album_id = value["id"];
				    		}
				    	}

				        if(album_id == 0) {

				            bridge.send("VKWebAppCallAPIMethod", {"method": "photos.createAlbum", "params": {"title": "Стилист", "description": textPublication, "v":"5.131", "access_token":token}})
				            .then(data_album => {
				                album_id = data_album["response"]["id"];
				            })

				            .catch(error_album => {
				                setPopout(null);
				                return;
				            })
				        }

				        setTimeout(function () {
				        	bridge.send("VKWebAppCallAPIMethod", {"method": "photos.getUploadServer", "params": { "album_id": album_id, "v":"5.131", "access_token":token }})
								.then(data_upload => {
									let upload_url = data_upload["response"]["upload_url"];
									axios.post("image?" + getParams, { url: resultImageUrlPost, upload_url: upload_url })
										.then(function (data_post) {
										  	bridge.send("VKWebAppCallAPIMethod", {"method": "photos.save", "params": { "album_id": album_id, "hash": data_post["data"]["hash"], "server": data_post["data"]["server"], "photos_list": data_post["data"]["photos_list"], "aid": data_post["data"]["aid"], "v":"5.131", "description": textPublication, "access_token":token }})
		        								.then(data_save => {
		        									setPublicationPost("photo"+fetchedUser.id+"_"+data_save["response"][0]["id"]);
		        									setPublicationStory(data_save["response"][0]["sizes"][2]["url"]);

		            								if(type == 'post') {
		            									openVKPost("photo"+fetchedUser.id+"_"+data_save["response"][0]["id"]);
		            									setPopout(null);
		            								}
		        								})

		        								.catch(error => {
													setPopout(null);
												});

										})

										.catch(function (error) {
										    setPopout(null);
										});
								})

								.catch(error => {
			        				setPopout(null);
			    				});
				        }, 500);

				    })

		    .catch(error => {
				setPopout(null);
			});

		})

        .catch(error => {
			setPopout(null);
			console.log("error: ");
			console.log(error);
		});
	}

	function openVKPost (returnImg = null) {
		let imgPost = "";
		if(publicationPost) {
			imgPost = publicationPost;
		} else {
			imgPost = returnImg;
		}

		if(imgPost) {
			bridge.send("VKWebAppShowWallPostBox", {"message": textPublication, "attachments": imgPost})
			.then((data) => { 

				if(openGroupPage == 1) {
					if(publicationStory) {
						openModal('group', 'story');
					} else {
						openModal('group');
					}
				} else {
					if(publicationStory) {
						openModal('story');
					}
				}
				axios.get("event?type=post&" + getParams);
			});
		} else {
			publicationResult('post');
		}
	}

	function openVKStory () {
		if(publicationStory) {
			bridge.send("VKWebAppShowStoryBox", {"background_type": "image", "url": publicationStory, "attachment": { "text": "open", "type": "url", "url": urlPublication }})
			.then((data) => { 
				setPublicationStory(null);
			});
		}
	}

	function groupModal () {
		let j = 1;
		{groupList.map((groupId) => {
	    	bridge.send('VKWebAppJoinGroup', { group_id: groupId })
	    	.then((data) => { 
				if (data.result) {
				  	if(j == 0) {
				  		setOpenGroupPage(1);
				  	} else {
				  		setOpenGroupPage(0);
				  	}
				  	j = 1;
				}
				})

				.catch((error) => {
					setOpenGroupPage(1);
					j = 0;
				});
	    })};

	 	if(publicationPost) {
	 		openModal('story');
	 	} else {
	 		openModal('post');
	 	}
	}

	function group (typeEvent) {
		let j = 1;
		if(typeEvent == 1) {
			axios.get("event?type=join_1&" + getParams);
			{groupList.map((groupId) => {
		    	bridge.send('VKWebAppJoinGroup', { group_id: groupId })
		    	.then((data) => { 
					if (data.result) {
					  	if(j == 0) {
					  		setOpenGroupPage(1);
					  	} else {
					  		setOpenGroupPage(0);
					  	}
					  	j = 1;
					}
					})

					.catch((error) => {
						setOpenGroupPage(1);
						j = 0;
					});
		    })};

			if(openAccessPage == 1) {
				setActivePanel('access');
			} else {
				setPopout(<ScreenSpinner size='large' />);
				openResult();
			}
		} else {
			if(r == true) {
				if(openAccessPage == 1) {
					setActivePanel('access');
				} else {
					setPopout(<ScreenSpinner size='large' />);
					openResult();
					axios.get("event?type=cancel_1&" + getParams);
				}
			}
		}
	}

	function access (typeEvent) {
		if(typeEvent == 1) {
			axios.get("event?type=join_2&" + getParams);
			bridge.send("VKWebAppGetAuthToken", {"app_id": appId, "scope": "photos"})
	            .then(data => {
	            	setAccessToken(data["access_token"]);
	            	setPopout(<ScreenSpinner size='large' />);
	            	openResult(1);
	            })

	            .catch(error => {
					setPopout(<ScreenSpinner size='large' />);
					openResult();
				});
		} else {
			if(r == true) {
				if(openAccessPage == 1) {
					setPopout(<ScreenSpinner size='large' />);
					openResult();
					axios.get("event?type=cancel_2&" + getParams);
				}
			}
		}
	}

	function startGetResult () {
		setPopout(<ScreenSpinner size='large' />);
		bridge.send('VKWebAppShowBannerAd', {
		  	banner_location: 'bottom'
		});
		setTimeout(function () {
			setPopout(null);
			setActivePanel('load');
			setTimeout(function () {
	            $(".load-txt").text("Подбираем подходящий образ...");
	        }, 5000);

	        setTimeout(function () {
	            $(".load-txt").text("Кажется, мы что-то нашли...");
	        }, 10000);

	        setTimeout(function () {
	            $(".load-txt").text("Ура! Ваш новый обаз найден");
	        }, 15000);

	        setTimeout(function () {
	            $(".load-txt").text("Осталось совсем немного...");
	        }, 20000);

	        setTimeout(function () {
	        	bridge.send('VKWebAppHideBannerAd');
	        	bridge.send('VKWebAppShowNativeAds', { ad_format: 'interstitial' });

	        	if(openGroupPage == 1) {
	        		setActivePanel('group');
	        	} else {
	        		if(openAccessPage == 1) {
	        			setActivePanel('access');
	        		} else {
	        			openResult();
	        		}
	        	}
	        }, 25000);
		}, 3000);
	}

	return [
		<View activePanel={activePanel}>

			<Panel id="error_app">
				<Group>
					<Placeholder
				        icon={<Icon56ErrorOutline />}
				        header="Приложение временно недоступно"
				        action={<Button size="m" sizeY="regular" onClick={() => { bridge.send("VKWebAppClose", {"status": "success"});  }}>Закрыть приложение</Button>}
			        >
			        	Пожалуйста, попробуйте запустить приложение через несколько минут
			        </Placeholder>
				</Group>
			</Panel>

			<Panel id="start">
				<PanelHeader>Стилист</PanelHeader>
				<Group>
					<br/>

					<img src={imgStart} style={{ borderRadius: "20px", width: "70%", display: "block", marginLeft: "auto", marginRight: "auto" }} />
					<b><Div style={{ textAlign: "center "}}>
						Добро пожаловать в приложение, где мы гарантируем незабываемый образ только для Вас! Мы рады предложить вам уникальную возможность преобразить ваш стиль и подчеркнуть вашу индивидуальность.
					</Div></b>
					<Div>
						<Button stretched size="l" sizeY="regular" mode="primary" onClick={() => { startGetResult(); getResult('ava'); }} >
							Запустить
						</Button>
					</Div>
				</Group>
			</Panel>

			<Panel id="load">
				<PanelHeader>Загрузка...</PanelHeader>
				<Group>
					<br/>
	                <div style={{ fontSize: "20px", textAlign: "center", marginLeft: "3%", marginRight: "3%" }}>Идёт обработка фотографии с вашего профиля</div>
	                <br/>
	                <img src={gifLoad} style={{ width: "60%", display: "block", marginLeft: "auto", marginRight: "auto", borderRadius: "8px" }}/>
	                <Div>
	                	<b><div style={{ fontSize: "20px", textAlign: "center" }} class="load-txt">Загружаем Ваше фото для анализа...</div></b>
                	</Div>
                </Group>
			</Panel>

			<Panel id="error">
				<PanelHeader>Уведомление</PanelHeader>
				<Group>
				<Div style={{ textAlign: "center" }}>
					Мы не смогли определить Ваше лицо на аватаре! Попробуйте использовать другое фото с галереи либо обновите аватар на Вашей странице и возвращайтесь снова.
				</Div>
				<Div style={{ textAlign: "center", color: "red" }}>
					<b>Внимание! На фото должно быть одно лицо в хорошем качестве.</b>
				</Div>
				<img src={imgWarn} style={{ width: "250px", display: "block", marginLeft: "auto", marginRight: "auto", borderRadius: "20px" }} />
				<Div>
					<File
			            stretched="true"
			            size="l"
			            align="center"
			            id="image"
			            onChange={ (e) => { imageDownload(e); } }
		            >
		            	Загрузить фотографию
		            </File>
			    </Div>
			    </Group>
				{snackbar}
			</Panel>

			<Panel id="group">
				<PanelHeader>Уведомление</PanelHeader>
				<Group>
					<b><Div style={{ textAlign: "center" }}>
						Проходите новые тесты уже сейчас, подпишитесь на наше сообщество ✅ Там мы публикуем новые интересные тесты и не только 👇
					</Div></b>
					<img src={imgGroups} style={{ width: "45%", display: "block", marginLeft: "auto", marginRight: "auto" }} />
					<Div>
						<Button stretched size="l" sizeY="regular" mode="primary" onClick={() => group(1)}>{texts[0][0]}</Button><br/>
						<Button stretched size="l" sizeY="regular" mode="secondary" onClick={() => group(2)}>{texts[0][1]}</Button>
					</Div>
				</Group>
			</Panel>

			<Panel id="access">
				<PanelHeader>Уведомление</PanelHeader>
				<Group>
					<b><Div style={{ textAlign: "center" }}>
						Поделитесь своим результатом у себя на странице! Ваши друзья точно будут удивлены таким сходством и оценят это лайком 👍
					</Div></b>
					<img src={imgAccess} style={{ width: "45%", display: "block", marginLeft: "auto", marginRight: "auto" }} />
